function getApiBaseUrl(){const i=window.MAGALU_RUNTIME_CONFIG&&window.MAGALU_RUNTIME_CONFIG.apiBaseUrl;return i?i.replace(/\/$/,""):""}function buildApiUrl(i){const e=i.startsWith("/")?i:`/${i}`,r=getApiBaseUrl();return r?`${r}${e}`:e}function withApiDefaults(i={}){const e=new Headers(i.headers||{});return e.set("ngrok-skip-browser-warning","true"),{...i,headers:e}}window.magaluApi={buildApiUrl:buildApiUrl,withApiDefaults:withApiDefaults};